namespace sv_31408eb2b8064bb1b07e01818e0143f0.Services;

/// <summary>
/// Scoped service that holds the currently selected warehouse for a single circuit.
/// Each Blazor Server circuit gets its own instance, so concurrent users are isolated.
/// </summary>
public sealed class WarehouseStateService
{
    private string _currentWarehouseId = "WH-1";

    public event Action? OnWarehouseChanged;

    public string CurrentWarehouseId
    {
        get => _currentWarehouseId;
        set
        {
            if (_currentWarehouseId == value)
                return;

            _currentWarehouseId = value;
            OnWarehouseChanged?.Invoke();
        }
    }

    public static IReadOnlyList<(string Id, string Name)> AvailableWarehouses { get; } =
    [
        ("WH-1", "Warehouse A — East"),
        ("WH-2", "Warehouse B — West"),
        ("WH-3", "Warehouse C — Central"),
    ];
}

namespace sv_31408eb2b8064bb1b07e01818e0143f0.Services;

/// <summary>
/// Scoped service that provides low-stock alert counts and notifies all
/// subscribed components when fresh data arrives. Because it is scoped,
/// each Blazor Server circuit has its own instance and its own alert state.
/// </summary>
public sealed class InventoryAlertService
{
    private readonly Random _random = new();

    /// <summary>
    /// Fired after <see cref="RefreshLowStockCountAsync"/> completes.
    /// Every component that subscribes will be notified — not just the
    /// one that triggered the poll.
    /// </summary>
    public event Func<Task>? OnAlertCountChanged;

    public int CurrentLowStockCount { get; private set; }

    /// <summary>
    /// Simulates a database query that returns the number of items
    /// below minimum stock levels for the given warehouse.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate async I/O latency
        int count = _random.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Polls for fresh data and notifies all subscribers.
    /// </summary>
    public async Task RefreshLowStockCountAsync(string warehouseId)
    {
        CurrentLowStockCount = await GetLowStockCountAsync(warehouseId);

        if (OnAlertCountChanged is not null)
            await OnAlertCountChanged.Invoke();
    }
}

