@page "/dashboard"
@rendermode InteractiveServer
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Selected Warehouse</h5>
                <p class="card-text fs-4">@CurrentWarehouseName</p>
                <p class="text-muted small">ID: @WarehouseState.CurrentWarehouseId</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="card-text fs-1">
                    <AlertBadge />
                </p>
                <p class="text-muted small">items below minimum level</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="card-text">
                    @if (_isPolling)
                    {
                        <span class="badge bg-success">Active — every 10 s</span>
                    }
                    else
                    {
                        <span class="badge bg-secondary">Stopped</span>
                    }
                </p>
                <p class="text-muted small">Last refresh: @_lastRefresh?.ToString("T")</p>
            </div>
        </div>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;
    private bool _isPolling;
    private DateTime? _lastRefresh;

    private string CurrentWarehouseName =>
        WarehouseStateService.AvailableWarehouses
            .FirstOrDefault(w => w.Id == WarehouseState.CurrentWarehouseId).Name
        ?? "Unknown";

    protected override void OnInitialized()
    {
        WarehouseState.OnWarehouseChanged += HandleWarehouseChanged;
        AlertService.OnAlertCountChanged += HandleAlertCountChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            // Kick off an initial refresh so we don't show stale data
            await AlertService.RefreshLowStockCountAsync(WarehouseState.CurrentWarehouseId);
            _lastRefresh = DateTime.Now;
            StartPolling();
            StateHasChanged();
        }
    }

    private void StartPolling()
    {
        StopPolling();
        _cts = new CancellationTokenSource();
        _isPolling = true;
        _ = PollLoopAsync(_cts.Token);
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _isPolling = false;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));

        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await AlertService.RefreshLowStockCountAsync(WarehouseState.CurrentWarehouseId);
                _lastRefresh = DateTime.Now;
                await InvokeAsync(StateHasChanged);
            }
        }
        catch (OperationCanceledException)
        {
            // Expected when the component disposes or warehouse changes
        }
    }

    private void HandleWarehouseChanged()
    {
        // Restart polling against the new warehouse immediately
        InvokeAsync(async () =>
        {
            await AlertService.RefreshLowStockCountAsync(WarehouseState.CurrentWarehouseId);
            _lastRefresh = DateTime.Now;
            StartPolling();
            StateHasChanged();
        });
    }

    private Task HandleAlertCountChanged() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        StopPolling();
        WarehouseState.OnWarehouseChanged -= HandleWarehouseChanged;
        AlertService.OnAlertCountChanged -= HandleAlertCountChanged;
    }
}

